INSERT INTO preguntas (id, tema, pregunta, opcion_a, opcion_b, opcion_c, opcion_d, respuesta_correcta, justificacion) VALUES
  (1, 'Conceptos fundamentales de POO', '¿Qué es la abstracción en Programación Orientada a Objetos?', 'Crear múltiples objetos a partir de una sola clase', 'Representar las características esenciales de un objeto del mundo real, ignorando los detalles irrelevantes', 'Heredar atributos y métodos de una clase padre', 'Ocultar los atributos de una clase usando private', 'b', 'La abstracción consiste en identificar y modelar solo las propiedades y comportamientos relevantes de una entidad del mundo real para el problema que se desea resolver.'),
  (2, 'Conceptos fundamentales de POO', '¿Cuál es la definición correcta de una clase en POO?', 'Un archivo con extensión .java que contiene el método main()', 'Una plantilla o molde que define los atributos y métodos que tendrán los objetos creados a partir de ella', 'Un objeto concreto que existe en memoria durante la ejecución', 'Una función que retorna un valor entero', 'b', 'Una clase es una plantilla (blueprint) que define la estructura (atributos) y el comportamiento (métodos) común a un conjunto de objetos del mismo tipo.'),
  (3, 'Conceptos fundamentales de POO', '¿Cuál es la diferencia principal entre una clase y un objeto?', 'La clase es la plantilla de diseño y el objeto es una instancia concreta creada a partir de esa plantilla', 'La clase contiene el método main() y el objeto no', 'No hay diferencia, son sinónimos en Java', 'La clase se ejecuta y el objeto se compila', 'a', 'La clase define la estructura y comportamiento; el objeto es una entidad concreta creada en memoria que posee valores específicos en sus atributos.'),
  (4, 'Conceptos fundamentales de POO', '¿Qué significa ''instanciar'' una clase?', 'Compilar el archivo de la clase sin errores', 'Crear un objeto concreto en memoria a partir de la definición de una clase usando la palabra new', 'Escribir el código fuente de la clase en un archivo .java', 'Declarar los atributos de la clase como private', 'b', 'Instanciar es el proceso de crear un objeto (instancia) en memoria utilizando el operador new seguido de un constructor de la clase.'),
  (5, 'Conceptos fundamentales de POO', '¿Cuál de las siguientes afirmaciones sobre un objeto es CORRECTA?', 'Un objeto es una instancia de una clase que ocupa espacio en memoria y tiene valores concretos en sus atributos', 'Un objeto se define con la palabra clave class', 'Un objeto no puede llamar a los métodos de su clase', 'Un objeto solo puede tener atributos, no métodos', 'a', 'Un objeto es una instancia concreta de una clase que reside en memoria RAM durante la ejecución del programa, con valores específicos asignados a cada uno de sus atributos.'),
  (6, 'Conceptos fundamentales de POO', 'Si se tiene la línea: Persona juanito = new Persona(); ¿qué representa ''juanito''?', 'El tipo de dato primitivo', 'El nombre del archivo .java', 'Una referencia al objeto (instancia) de tipo Persona creado en memoria', 'El nombre de la clase', 'c', 'juanito es una variable de referencia que apunta al objeto de tipo Persona que fue creado en memoria con el operador new.'),
  (7, 'Conceptos fundamentales de POO', '¿Cuál de las siguientes NO es una característica de la Programación Orientada a Objetos?', 'Programación secuencial pura', 'Abstracción', 'Encapsulación', 'Polimorfismo', 'a', 'La programación secuencial pura es un paradigma diferente. Los pilares de la POO son: Abstracción, Encapsulación, Herencia y Polimorfismo.'),
  (8, 'Conceptos fundamentales de POO', '¿Qué sucede cuando se ejecuta: Persona p1 = new Persona(); Persona p2 = new Persona();?', 'Se crean dos objetos independientes en memoria, cada uno con sus propios atributos', 'Se crea un arreglo de dos Personas automáticamente', 'Se crea un solo objeto compartido por p1 y p2', 'Se produce un error porque no puede haber dos objetos de la misma clase', 'a', 'Cada uso de new crea un objeto independiente en memoria con su propio espacio para atributos. p1 y p2 son referencias a objetos diferentes.'),
  (9, 'Conceptos fundamentales de POO', 'En el contexto de POO, ¿qué relación existe entre ''instancia'' y ''objeto''?', 'Son conceptos completamente diferentes', 'Son sinónimos: ambos se refieren a una entidad concreta creada a partir de una clase', 'Una instancia es una clase y un objeto es un método', 'Un objeto puede tener muchas instancias dentro de él', 'b', 'Los términos ''instancia'' y ''objeto'' se usan de manera intercambiable. Cuando se dice ''instanciar una clase'', se crea un objeto (instancia) de esa clase.'),
  (10, 'Conceptos fundamentales de POO', '¿Por qué se dice que una clase es un ''tipo de dato definido por el usuario''?', 'Porque Java no tiene tipos de datos propios', 'Porque las clases solo almacenan cadenas de texto', 'Porque el usuario introduce datos por teclado al ejecutar el programa', 'Porque el programador define su propia estructura con atributos y métodos, similar a como int o float son tipos predefinidos', 'd', 'Al crear una clase, el programador define un nuevo tipo de dato con su propia estructura (atributos) y operaciones (métodos), extendiendo los tipos primitivos que ofrece Java.'),
  (11, 'Atributos y Métodos', '¿Qué es un atributo en una clase Java?', 'El nombre del archivo donde se guarda la clase', 'Una variable declarada dentro de la clase que representa una característica del objeto', 'Una instrucción de control como if o for', 'Una función que retorna un valor', 'b', 'Un atributo (también llamado variable de instancia o característica) es una variable declarada dentro de la clase que almacena información sobre el estado del objeto.'),
  (12, 'Atributos y Métodos', '¿Qué es un método en una clase Java?', 'El constructor de la clase', 'Una variable que se declara dentro de main()', 'Un bloque de código que define un comportamiento del objeto y puede recibir parámetros y retornar valores', 'Un atributo de tipo String', 'c', 'Un método (también llamado función o comportamiento) es un bloque de código que pertenece a la clase y define una acción que los objetos pueden realizar.'),
  (13, 'Atributos y Métodos', '¿Cuál es la diferencia entre un parámetro y un argumento?', 'El argumento se declara en la clase y el parámetro en el main()', 'El parámetro es la variable declarada en la definición del método; el argumento es el valor que se pasa al invocarlo', 'No hay diferencia, son lo mismo', 'El parámetro es un tipo de dato y el argumento es un método', 'b', 'El parámetro es la variable que aparece en la firma del método (ej: int edad). El argumento es el valor concreto que se envía al llamar al método (ej: setEdad(25), donde 25 es el argumento).'),
  (14, 'Atributos y Métodos', '¿Qué significa que un método tiene ''void'' como tipo de retorno?', 'Que el método no retorna ningún valor al finalizar su ejecución', 'Que el método no recibe parámetros', 'Que el método es privado', 'Que el método retorna un valor entero', 'a', 'La palabra clave void indica que el método no devuelve ningún valor. Si se necesitara retornar algo, se usaría el tipo correspondiente (int, String, float, etc.) y la instrucción return.'),
  (15, 'Atributos y Métodos', 'En la clase Persona del ejemplo de clase, ¿cuál es el tipo de retorno del método getEdad()?', 'void', 'String', 'float', 'int', 'd', 'El método getEdad() retorna un valor de tipo int porque el atributo edad fue declarado como private int edad, y el getter devuelve ese mismo tipo.'),
  (16, 'Atributos y Métodos', '¿Qué hace la palabra clave ''this'' dentro de un método de la clase?', 'Declara una variable local dentro del método', 'Crea un nuevo objeto de la clase', 'Llama al constructor de la clase padre', 'Hace referencia al objeto actual que está ejecutando el método', 'd', 'La palabra clave this es una referencia al objeto actual. Se usa para distinguir entre atributos de la clase y parámetros del método cuando tienen el mismo nombre, como en: this.edad = edad.'),
  (17, 'Atributos y Métodos', '¿Cuál de las siguientes es la firma correcta de un método que recibe un nombre y retorna un saludo?', 'public String saludar(String nombre)', 'String public saludar(nombre)', 'public saludar(String nombre): String', 'public void saludar(String nombre)', 'a', 'Como el método debe retornar un saludo (cadena de texto), su tipo de retorno debe ser String. La opción a) usa void y no retornaría nada. La sintaxis correcta en Java es: modificador tipoRetorno nombreMetodo(parametros).'),
  (18, 'Atributos y Métodos', 'En el ejemplo de la clase Paciente, ¿qué hace el método calcFuerza(float fuerzaBase)?', 'Multiplica fuerzaBase por el factorAjuste del paciente y retorna el resultado', 'Asigna un nuevo valor a fuerzaBase', 'Retorna el valor del atributo factorAjuste', 'Imprime en pantalla la fuerza del paciente', 'a', 'El método calcFuerza recibe un parámetro fuerzaBase y retorna fuerzaBase * this.factorAjuste, es decir, calcula la fuerza ajustada del paciente.'),
  (19, 'Atributos y Métodos', '¿Qué retorna el método revisarEnergiaCritica() de la clase Paciente?', 'Nada, es void', 'Un String indicando el nivel de energía', 'Un valor boolean: true si la energía biónica es menor a 15.0, false en caso contrario', 'Un valor float con la energía actual', 'c', 'El método retorna this.energiaBionica < 15.0f, que es una expresión booleana. Si la energía es menor a 15, retorna true (energía crítica); en caso contrario, retorna false.'),
  (20, 'Atributos y Métodos', '¿Para qué sirve el método toString() en una clase Java?', 'Para convertir un número entero a String', 'Para retornar una representación en texto del objeto, útil al imprimirlo con System.out.println', 'Para leer datos del teclado', 'Para comparar dos objetos', 'b', 'El método toString() se sobrescribe (@Override) para devolver una cadena que describe el estado del objeto. Se invoca automáticamente cuando se imprime un objeto con System.out.println.'),
  (21, 'UML y Diagramas de Clase', '¿Qué significan las siglas UML?', 'Universal Method Language', 'User Machine Logic', 'Unique Model Library', 'Unified Modeling Language (Lenguaje Unificado de Modelado)', 'd', 'UML significa Unified Modeling Language. Es un lenguaje estándar para visualizar, especificar, construir y documentar los artefactos de un sistema de software.'),
  (22, 'UML y Diagramas de Clase', '¿Cuántas secciones tiene un diagrama de clase en UML?', '2: nombre y métodos', '1: solo el nombre de la clase', '4: nombre, atributos, métodos y constructores separados', '3: nombre de la clase, atributos y métodos', 'd', 'Un diagrama de clase UML se divide en tres compartimentos: el nombre de la clase (arriba), los atributos (en medio) y los métodos o comportamientos (abajo).'),
  (23, 'UML y Diagramas de Clase', 'En un diagrama de clase UML, ¿qué significa el símbolo ''+'' antes de un atributo o método?', 'Que es protegido (protected)', 'Que es estático (static)', 'Que es público (public)', 'Que es privado (private)', 'c', 'En UML, el símbolo + indica visibilidad pública (public), el símbolo - indica privada (private), y el símbolo # indica protegida (protected).'),
  (24, 'UML y Diagramas de Clase', 'En un diagrama de clase UML, ¿qué símbolo se usa para representar un atributo privado?', '# (numeral)', '* (asterisco)', '+ (más)', '- (menos)', 'd', 'El símbolo - (menos) representa visibilidad private en UML. Esto se usa cuando se aplica encapsulación, ocultando los atributos de acceso directo externo.'),
  (25, 'UML y Diagramas de Clase', '¿Cómo se representa el atributo ''nombre'' de tipo String con visibilidad pública en un diagrama UML?', 'nombre: public String', '- nombre: String', '+ nombre: String', 'String + nombre', 'c', 'En UML la notación es: visibilidad nombre: tipo. Para un atributo público de tipo String se escribe: + nombre: String.'),
  (26, 'UML y Diagramas de Clase', '¿Cómo se representa un método público que no retorna valor y se llama saludar() en UML?', '+ saludar(): String', 'saludar() = void', '- saludar(): void', '+ saludar(): void', 'd', 'La notación UML para métodos es: visibilidad nombre(parámetros): tipoRetorno. Un método público sin retorno se escribe: + saludar(): void.'),
  (27, 'UML y Diagramas de Clase', '¿Cómo se representa en UML un atributo privado constante llamado MAX_VALOR de tipo int?', '# MAX_VALOR: int {final}', '+ MAX_VALOR: int', '- MAX_VALOR: int {readOnly}', '- MAX_VALOR: int', 'c', 'En UML, un atributo constante se puede representar con la restricción {readOnly} o escribiendo el nombre en MAYÚSCULAS. La visibilidad private se indica con el símbolo -.'),
  (28, 'UML y Diagramas de Clase', '¿Cómo se representa un atributo de clase (static) en un diagrama de clase UML?', 'Subrayando el nombre del atributo', 'Poniéndolo en una sección separada del diagrama', 'Con el símbolo # antes del nombre', 'Con un asterisco * después del tipo', 'a', 'En UML, los atributos y métodos de clase (static) se representan subrayándolos, lo que los distingue de los atributos de instancia normales.'),
  (29, 'UML y Diagramas de Clase', 'En el diagrama de clase Saludo visto en la Tarea 1, ¿qué atributo y método se mostraban originalmente?', '+ texto: int y + decir(): String', '+ textoSaludo: String y + saludar(): void', '- textoSaludo: String y - saludar(): void', '# textoSaludo: String y # saludar(): void', 'b', 'En el diagrama original de la clase Saludo, el atributo textoSaludo era de tipo String con visibilidad pública (+) y el método saludar() era público y retornaba void.'),
  (30, 'UML y Diagramas de Clase', '¿Cómo se representa en UML el método setter setEdad(int edad): void con visibilidad pública?', '- setEdad(edad: int): void', '+ setEdad(edad: int): void', '# setEdad(int): void', '+ setEdad(): int', 'b', 'Un setter público se representa con + (public), el nombre del método, sus parámetros con nombre y tipo entre paréntesis, y el tipo de retorno void tras los dos puntos.'),
  (31, 'Tipos de dato y palabras clave Java', '¿Cuál de los siguientes es un tipo de dato primitivo entero en Java?', 'Scanner', 'String', 'System', 'int', 'd', 'int es un tipo de dato primitivo que almacena números enteros de 32 bits. String, Scanner y System son clases, no tipos primitivos.'),
  (32, 'Tipos de dato y palabras clave Java', '¿Cuál es la diferencia entre float y double en Java?', 'No hay diferencia, son sinónimos', 'double solo almacena números positivos', 'float usa 32 bits (precisión simple) y double usa 64 bits (precisión doble)', 'float almacena caracteres y double almacena enteros', 'c', 'float ocupa 32 bits y ofrece aproximadamente 7 dígitos de precisión. double ocupa 64 bits y ofrece aproximadamente 15 dígitos de precisión. double es el tipo decimal por defecto en Java.'),
  (33, 'Tipos de dato y palabras clave Java', '¿Qué tipo de dato se usa en Java para almacenar un solo carácter?', 'String', 'char', 'boolean', 'byte', 'b', 'El tipo char almacena un solo carácter Unicode de 16 bits, encerrado entre comillas simples, por ejemplo: char genero = ''M'';'),
  (34, 'Tipos de dato y palabras clave Java', '¿Cuál de las siguientes es una palabra clave (keyword) reservada de Java?', 'System', 'Persona', 'Scanner', 'public', 'd', 'public es una palabra reservada de Java que indica visibilidad pública. Scanner y System son clases de la biblioteca estándar, y Persona es un nombre de clase definido por el usuario.'),
  (35, 'Tipos de dato y palabras clave Java', '¿Qué tipo de dato se usa para la variable ''nombre'' en: private String nombre;?', 'Un tipo de dato de referencia (clase String de Java)', 'Un tipo primitivo char', 'Un tipo primitivo de texto', 'Un arreglo de caracteres', 'a', 'String no es un tipo primitivo, sino una clase de Java (tipo de referencia). Los tipos primitivos son: byte, short, int, long, float, double, char y boolean.'),
  (36, 'Tipos de dato y palabras clave Java', '¿Cuál de las siguientes declaraciones de variable es correcta en Java?', 'float altura = 1.75f;', 'String = "Hola";', 'char genero = "M";', 'int 2edad = 25;', 'a', 'En Java, un literal float requiere la letra f al final. La opción a) es inválida porque el nombre empieza con número. La c) no tiene nombre de variable. La d) usa comillas dobles para char (debe usar simples: ''M'').'),
  (37, 'Tipos de dato y palabras clave Java', '¿Cuáles son los 8 tipos de datos primitivos en Java?', 'byte, short, int, long, float, double, char, boolean', 'int, float, String, char, boolean, double, long, Scanner', 'int, float, char, String, void, double, byte, boolean', 'integer, floating, character, string, bool, decimal, long, short', 'a', 'Los 8 tipos primitivos de Java son: byte, short, int, long (enteros), float, double (decimales), char (carácter) y boolean (verdadero/falso). String y void NO son tipos primitivos.'),
  (38, 'Tipos de dato y palabras clave Java', '¿Cuál es el valor por defecto de un atributo de tipo int en Java cuando no se inicializa explícitamente?', 'null', '0', '-1', 'No tiene valor, da error', 'b', 'En Java, los atributos de instancia de tipo numérico entero (byte, short, int, long) se inicializan automáticamente en 0 si no se les asigna un valor.'),
  (39, 'Tipos de dato y palabras clave Java', '¿Qué palabra clave se usa para indicar que una clase puede ser accesible desde cualquier paquete?', 'static', 'private', 'public', 'final', 'c', 'La palabra clave public indica que la clase (o miembro) es accesible desde cualquier otro paquete. Si se omite, la clase solo es accesible dentro de su propio paquete (acceso por defecto).'),
  (40, 'Tipos de dato y palabras clave Java', '¿Cuál es la diferencia entre String y char en Java?', 'Ambos son tipos primitivos que almacenan texto', 'No hay diferencia', 'char almacena un solo carácter entre comillas simples y String almacena una cadena de caracteres entre comillas dobles', 'String almacena un solo carácter y char almacena una cadena', 'c', 'char es un tipo primitivo para un solo carácter (ej: ''A''), mientras que String es una clase que almacena secuencias de caracteres (ej: "Hola mundo").'),
  (41, 'Instanciación, parámetros y retorno', '¿Cuál es la sintaxis correcta para instanciar un objeto de la clase Persona?', 'Persona p = create Persona();', 'Persona p = new Persona();', 'Persona p = Persona();', 'new Persona p = Persona();', 'b', 'La sintaxis para instanciar es: NombreClase variable = new NombreClase(argumentos); El operador new reserva memoria para el objeto y llama al constructor.'),
  (42, 'Instanciación, parámetros y retorno', '¿Qué operador se utiliza en Java para crear un nuevo objeto en memoria?', 'make', 'new', 'create', 'instance', 'b', 'El operador new se encarga de reservar espacio en la memoria heap para el nuevo objeto y de invocar al constructor correspondiente de la clase.'),
  (43, 'Instanciación, parámetros y retorno', '¿Qué sucede internamente cuando se ejecuta: Paciente p = new Paciente(1, "Ana", 30);?', 'Se eliminan los objetos Paciente anteriores', 'Se reserva memoria para el objeto y se invoca el constructor que recibe int, String, int para inicializar atributos', 'Se crea la clase Paciente por primera vez', 'Se crea un archivo llamado Ana.java', 'b', 'El operador new reserva memoria, y luego se ejecuta el constructor que coincide con los parámetros (int, String, int), inicializando idPaciente=1, nombre="Ana", edad=30.'),
  (44, 'Instanciación, parámetros y retorno', '¿Cuál es la diferencia entre declarar y instanciar un objeto?', 'Declarar se hace en UML e instanciar se hace en Java', 'Son lo mismo', 'Declarar es crear el objeto e instanciar es definir sus métodos', 'Declarar es definir la variable de referencia con su tipo; instanciar es crear el objeto en memoria con new', 'd', 'Declarar: Persona p; (solo crea la referencia, vale null). Instanciar: p = new Persona(); (crea el objeto en memoria). Se pueden hacer juntas: Persona p = new Persona();'),
  (45, 'Instanciación, parámetros y retorno', 'Si un método se define como: public float calcFuerza(float fuerzaBase), ¿cuántos parámetros recibe y de qué tipo?', 'Un parámetro de tipo float', 'Cero parámetros', 'Dos parámetros de tipo float', 'Un parámetro de tipo int', 'a', 'El método calcFuerza recibe exactamente un parámetro llamado fuerzaBase de tipo float. El tipo que aparece antes del nombre del método (float) es el tipo de retorno, no un parámetro.'),
  (46, 'Instanciación, parámetros y retorno', '¿Qué valor retorna el siguiente método?
public int getEdad() { return edad; }', 'El valor entero almacenado en el atributo edad del objeto', 'Un valor de tipo String con la edad', 'Un nuevo objeto de tipo int', 'Nada, es void', 'a', 'El método getEdad() tiene tipo de retorno int y usa return edad; para devolver el valor entero almacenado en el atributo edad del objeto actual.'),
  (47, 'Instanciación, parámetros y retorno', '¿Qué sucede si un método con tipo de retorno int NO incluye una instrucción return?', 'El programa se ejecuta pero sin retornar nada', 'Retorna null', 'Se produce un error de compilación', 'Retorna 0 automáticamente', 'c', 'Java exige que todo método con tipo de retorno diferente de void incluya una instrucción return con un valor del tipo correcto en todos los caminos de ejecución; de lo contrario, no compila.'),
  (48, 'Instanciación, parámetros y retorno', '¿Cuál es la salida al ejecutar: System.out.println(juanito); si juanito es un objeto Persona con toString() implementado?', 'Un error de compilación', 'La representación en texto del objeto definida en el método toString()', 'La dirección de memoria del objeto', 'El nombre de la clase: Persona', 'b', 'Cuando se pasa un objeto a println(), Java invoca automáticamente su método toString(). Si la clase tiene toString() sobrescrito, se muestra la cadena personalizada.'),
  (49, 'Instanciación, parámetros y retorno', 'En la línea: juanito.setEdad(una_edad); ¿qué rol cumple ''una_edad''?', 'Es una palabra clave de Java', 'Es el nombre del método', 'Es un atributo de la clase', 'Es el argumento que se pasa al parámetro del método setEdad', 'd', 'una_edad es una variable local que contiene el valor leído del teclado. Al pasarla como argumento a setEdad(), ese valor se asigna al parámetro del método.'),
  (50, 'Instanciación, parámetros y retorno', '¿Qué diferencia hay entre ''return'' y ''void''?', 'return es una instrucción que devuelve un valor al punto de llamada; void indica que el método no retorna ningún valor', 'void devuelve un valor vacío y return detiene el programa', 'return se usa solo en constructores y void en métodos normales', 'Son lo mismo, se usan indistintamente', 'a', 'void es un tipo de retorno que indica que el método no devuelve nada. return es una instrucción que termina el método y opcionalmente entrega un valor al código que lo llamó.'),
  (51, 'Encapsulación (private, getters, setters)', '¿Qué es la encapsulación en POO?', 'Usar la palabra clave static en todos los atributos', 'Ocultar los atributos de una clase declarándolos como private y proporcionar métodos públicos (getters y setters) para acceder a ellos', 'Heredar los atributos de otra clase', 'Crear múltiples constructores para una misma clase', 'b', 'La encapsulación protege los datos internos del objeto al declararlos private, controlando el acceso a través de métodos públicos (getters para leer, setters para modificar).'),
  (52, 'Encapsulación (private, getters, setters)', '¿Qué modificador de acceso se usa en Java para encapsular un atributo?', 'protected', 'static', 'private', 'public', 'c', 'La palabra clave private restringe el acceso al atributo solo dentro de la propia clase. Desde fuera de la clase, se necesitan métodos getters y setters para acceder al valor.'),
  (53, 'Encapsulación (private, getters, setters)', '¿Cuál es la estructura correcta de un método getter para el atributo ''private String nombre''?', 'public void getNombre() { return nombre; }', 'public String setNombre() { return nombre; }', 'private String getNombre() { return nombre; }', 'public String getNombre() { return this.nombre; }', 'd', 'Un getter debe ser público (para acceso externo), retornar el mismo tipo que el atributo (String) y usar return para devolver el valor. La opción a) usa void, por lo que no puede retornar.'),
  (54, 'Encapsulación (private, getters, setters)', '¿Cuál es la estructura correcta de un método setter para el atributo ''private int edad''?', 'public int setEdad(int edad) { this.edad = edad; }', 'public void setEdad(int edad) { this.edad = edad; }', 'private void setEdad(int edad) { this.edad = edad; }', 'public void setEdad() { this.edad = edad; }', 'b', 'Un setter debe ser público, tener retorno void (solo asigna), recibir un parámetro del mismo tipo que el atributo, y usar this.edad = edad para diferenciar atributo de parámetro.'),
  (55, 'Encapsulación (private, getters, setters)', '¿Qué error de compilación ocurre si desde main() se escribe: juanito.edad = 25; siendo edad un atributo private?', 'No ocurre ningún error', 'NullPointerException', 'Error de tipo de dato incompatible', 'Error: edad has private access in Persona', 'd', 'Al declarar edad como private, solo es accesible dentro de la clase Persona. Desde main() se debe usar el setter: juanito.setEdad(25);'),
  (56, 'Encapsulación (private, getters, setters)', '¿Cómo se clasifican los métodos accesorios?', 'En constructores y destructores', 'En estáticos y dinámicos', 'En getters (consultores) y setters (modificadores)', 'En públicos y privados', 'c', 'Los métodos accesorios se clasifican en: getters (o consultores), que retornan el valor del atributo, y setters (o modificadores), que asignan un nuevo valor al atributo.'),
  (57, 'Encapsulación (private, getters, setters)', 'En la clase Persona del ejemplo, ¿cómo se lee el nombre del objeto juanito desde main()?', 'juanito.nombre', 'juanito.getNombre()', 'Persona.getNombre(juanito)', 'getNombre(juanito)', 'b', 'Como el atributo nombre es private, se accede mediante el getter público: juanito.getNombre(). La opción a) daría error de acceso privado.'),
  (58, 'Encapsulación (private, getters, setters)', '¿Cuántos métodos getter y setter se necesitan si una clase tiene 5 atributos encapsulados?', '10 en total: 5 getters + 5 setters', '1 getter y 1 setter que manejen todos los atributos', 'Depende del tipo de dato de cada atributo', '5 en total (uno por atributo)', 'a', 'Cada atributo encapsulado necesita su propio getter (para leer) y su propio setter (para modificar). Con 5 atributos se requieren 5 getters + 5 setters = 10 métodos.'),
  (59, 'Encapsulación (private, getters, setters)', '¿Por qué es buena práctica encapsular los atributos de una clase?', 'Porque Java obliga a que todos los atributos sean private', 'Porque los atributos públicos no funcionan en Java', 'Porque protege la integridad de los datos al controlar cómo se leen y modifican, permitiendo validaciones', 'Porque hace el código más corto', 'c', 'La encapsulación permite controlar el acceso a los datos. En los setters se pueden agregar validaciones (ej: no permitir edad negativa), protegiendo la integridad del estado del objeto.'),
  (60, 'Encapsulación (private, getters, setters)', 'En la Tarea 3, ¿qué se pedía hacer con los proyectos de la Tarea 2?', 'Implementar la clase Scanner para leer datos', 'Agregar funciones constructor a cada clase', 'Crear arreglos de objetos para cada clase', 'Encapsular los atributos cambiándolos a private y codificar sus métodos set y get', 'd', 'La Tarea 3 pedía modificar al menos 10 proyectos para encapsular atributos (cambiar de public a private), codificar getters y setters, y representar la encapsulación en el diagrama UML.'),
  (61, 'Constructores y toString', '¿Qué es un constructor en Java?', 'Un método especial que se ejecuta automáticamente al crear un objeto con new, y sirve para inicializar atributos', 'Un método que retorna una cadena de texto', 'Un atributo de tipo estático', 'Un método que destruye un objeto cuando ya no se usa', 'a', 'Un constructor es un método especial que tiene el mismo nombre que la clase, no tiene tipo de retorno (ni siquiera void), y se invoca automáticamente al usar new para inicializar el objeto.'),
  (62, 'Constructores y toString', '¿Cuáles son las reglas que debe cumplir un constructor válido en Java?', 'Debe llamarse init() y ser estático', 'Debe ser siempre private y retornar un objeto', 'Debe tener tipo de retorno void y nombre diferente a la clase', 'Debe tener el mismo nombre que la clase, no tener tipo de retorno, y puede tener cero o más parámetros', 'd', 'Las reglas son: 1) Mismo nombre que la clase. 2) Sin tipo de retorno (ni void). 3) Puede tener 0 o más parámetros. 4) Se invoca con new. 5) Puede haber varios (sobrecarga).'),
  (63, 'Constructores y toString', '¿Qué es el ''constructor mínimo'' según la Tarea 4?', 'Un constructor con cero parámetros que inicializa cada atributo con un valor por defecto', 'Un constructor que no inicializa ningún atributo', 'Un constructor que recibe todos los atributos como parámetros', 'Un constructor que solo recibe un parámetro', 'a', 'El constructor mínimo (o sin parámetros) no recibe argumentos y asigna valores por defecto a todos los atributos, como en: public Persona() { this.edad = -2; this.nombre = "Sin nombre"; }'),
  (64, 'Constructores y toString', '¿Qué es el ''constructor máximo'' según la Tarea 4?', 'Un constructor sin parámetros', 'Un constructor que tiene tantos parámetros como atributos tiene la clase, inicializando cada uno con su parámetro correspondiente', 'Un constructor que solo inicializa un atributo', 'Un constructor que recibe más parámetros que atributos', 'b', 'El constructor máximo recibe un parámetro por cada atributo de la clase. Ejemplo: public Persona(int edad, float altura, double peso, char genero, String nombre) inicializa los 5 atributos.'),
  (65, 'Constructores y toString', '¿Qué es un ''constructor intermedio''?', 'Un constructor que hereda de otra clase', 'Un constructor con cero parámetros', 'Un constructor que se ejecuta entre el constructor mínimo y el máximo', 'Un constructor que recibe algunos parámetros (no todos), y los atributos restantes se inicializan con valores por defecto', 'd', 'Ejemplo de la clase Persona: public Persona(float altura, double peso, String nombre) recibe 3 parámetros e inicializa edad=-1 y genero=''?'' con valores por defecto.'),
  (66, 'Constructores y toString', '¿Qué es la sobrecarga de constructores?', 'Heredar constructores de otra clase', 'Tener múltiples constructores en una misma clase, cada uno con diferente lista de parámetros', 'Escribir el mismo constructor dos veces idéntico', 'Llamar a un constructor desde otro constructor', 'b', 'La sobrecarga permite definir varios constructores con diferente número o tipo de parámetros. Java elige cuál ejecutar según los argumentos pasados al hacer new.'),
  (67, 'Constructores y toString', 'Dado el código: Persona p = new Persona(1.75f, 80.0, "Luis"); ¿cuál constructor se ejecuta?', 'El constructor máximo (5 parámetros)', 'El constructor intermedio que recibe float, double y String', 'El constructor mínimo (sin parámetros)', 'Ninguno, da error de compilación', 'b', 'Java busca un constructor cuya firma coincida con los argumentos: (float, double, String). Ese es el constructor intermedio: public Persona(float altura, double peso, String nombre).'),
  (68, 'Constructores y toString', '¿Cuál es la salida de: System.out.println(new Persona()); si toString() retorna "Persona{edad=-2, nombre=Sin nombre}"?', 'Error de compilación', 'Persona{edad=-2, nombre=Sin nombre}', 'null', 'La dirección de memoria del objeto', 'b', 'Al hacer println de un objeto, Java invoca toString() automáticamente. El constructor mínimo asigna edad=-2 y nombre="Sin nombre", y toString() retorna esa representación.'),
  (69, 'Constructores y toString', '¿Qué anotación se coloca antes del método toString() cuando se redefine en una clase?', '@Static', '@Final', '@Override', '@Deprecated', 'c', '@Override indica que el método está sobrescribiendo un método heredado de la clase Object. Aunque no es obligatorio, es buena práctica para que el compilador verifique que la firma es correcta.'),
  (70, 'Constructores y toString', '¿Qué sucede si una clase no define ningún constructor explícitamente?', 'Java proporciona un constructor por defecto sin parámetros que inicializa atributos con valores por defecto', 'No se pueden crear objetos de esa clase', 'Se produce un error de compilación', 'Los atributos quedan sin inicializar y dan error al usarlos', 'a', 'Si no se define ningún constructor, Java genera automáticamente un constructor por defecto sin parámetros. Pero si se define al menos uno, Java ya no proporciona el constructor por defecto.'),
  (71, 'Atributos constantes (final) y de clase (static)', '¿Qué efecto tiene la palabra clave ''final'' al declarar un atributo en Java?', 'Hace que el atributo sea constante: su valor no puede cambiar después de ser asignado', 'Hace que el atributo sea de clase, compartido por todos los objetos', 'Hace que el atributo solo sea visible dentro del método main()', 'Hace que el atributo sea privado', 'a', 'La palabra clave final convierte al atributo en una constante. Una vez asignado un valor (en la declaración o en el constructor), no puede modificarse.'),
  (72, 'Atributos constantes (final) y de clase (static)', '¿Qué error ocurre si se intenta modificar un atributo declarado como final?', 'Error de compilación: cannot assign a value to final variable', 'No ocurre error, final es solo informativo', 'NullPointerException', 'El programa compila pero falla al ejecutarse', 'a', 'Java no permite la compilación si se intenta reasignar un valor a una variable final. El compilador genera el error: cannot assign a value to final variable nombreAtributo.'),
  (73, 'Atributos constantes (final) y de clase (static)', '¿Qué consecuencia tiene declarar un atributo como final respecto a los métodos setter?', 'El setter pasa a ser private automáticamente', 'No tiene ninguna consecuencia en los setters', 'El setter debe declararse también como final', 'Se debe eliminar el método setter de ese atributo, ya que su valor no se puede cambiar', 'd', 'Si un atributo es final (constante), no tiene sentido tener un setter porque el valor no se puede modificar. Intentar compilar un setter para un atributo final produce error.'),
  (74, 'Atributos constantes (final) y de clase (static)', '¿Qué significa que un atributo sea ''static'' (de clase) en Java?', 'Que el atributo solo es accesible desde el método main()', 'Que el atributo no puede cambiar de valor', 'Que el atributo se destruye al terminar el constructor', 'Que el atributo pertenece a la clase y es compartido por todos los objetos, existiendo una sola copia en memoria', 'd', 'Un atributo static pertenece a la clase, no a cada objeto individualmente. Todos los objetos comparten la misma copia, por lo que si uno lo modifica, el cambio es visible para todos.'),
  (75, 'Atributos constantes (final) y de clase (static)', '¿Cuál es un ejemplo típico de uso de un atributo static?', 'El tipo de implante de un paciente', 'El nombre de una persona', 'Un contador que lleva la cuenta de cuántos objetos se han creado de esa clase', 'La edad de un paciente', 'c', 'Un contador de objetos es el ejemplo clásico: static int contadorObjetos = 0; que se incrementa en cada constructor. Así se sabe cuántas instancias existen de la clase.'),
  (76, 'Atributos constantes (final) y de clase (static)', '¿Cómo se accede a un atributo static desde fuera de la clase?', 'No se puede acceder desde fuera de la clase', 'Usando la palabra clave this', 'Se puede acceder usando el nombre de la clase directamente: NombreClase.atributo', 'Solo a través de un objeto: objeto.atributo', 'c', 'Aunque también se puede acceder a través de un objeto, la forma recomendada es usar el nombre de la clase: Persona.contadorObjetos, ya que el atributo pertenece a la clase, no a un objeto particular.'),
  (77, 'Atributos constantes (final) y de clase (static)', '¿Qué modificación pedía la Tarea 6 respecto al constructor mínimo cuando un atributo se declara final?', 'Modificar el constructor mínimo para que inicialice el atributo final con un valor, ya que no podrá cambiarse después', 'Agregar un parámetro extra al constructor mínimo', 'Hacer el constructor mínimo static', 'Eliminar el constructor mínimo completamente', 'a', 'Un atributo final debe recibir su valor definitivo al momento de la construcción del objeto. El constructor mínimo debe asignarle un valor por defecto fijo, ya que no existirá setter para cambiarlo.'),
  (78, 'Atributos constantes (final) y de clase (static)', '¿Cuál es la convención de nombrado para constantes (final) en Java?', 'Todas las letras en MAYÚSCULAS separadas por guiones bajos (UPPER_SNAKE_CASE)', 'Empezar con minúscula seguido de mayúsculas', 'Prefijo ''const_'' seguido del nombre', 'camelCase como cualquier variable', 'a', 'La convención en Java es nombrar las constantes en MAYÚSCULAS con palabras separadas por guiones bajos, por ejemplo: MAX_VALOR, PI, NOMBRE_INSTITUCION.'),
  (79, 'Atributos constantes (final) y de clase (static)', '¿Es posible tener un atributo que sea ''static final'' simultáneamente?', 'No, son mutuamente excluyentes', 'Sí, pero solo para tipos String', 'Sí, significa que es una constante de clase compartida por todos los objetos y su valor no cambia', 'Solo si el atributo es público', 'c', 'static final es muy común en Java. Define una constante a nivel de clase: existe una sola copia (static) y no puede modificarse (final). Ejemplo: public static final double PI = 3.14159;'),
  (80, 'Atributos constantes (final) y de clase (static)', 'Si un atributo static se inicializa en 0 y se incrementa en cada constructor, ¿qué valor tendrá después de crear 3 objetos?', '3', '0', 'Depende del último objeto creado', '1', 'a', 'Al ser static, existe una sola copia compartida. Si se incrementa en el constructor (++contador), tras crear 3 objetos valdrá 3, sin importar desde qué referencia se lea.'),
  (81, 'Scanner y entrada de datos', '¿Qué clase de Java se usa para leer datos del teclado en tiempo de ejecución?', 'Scanner', 'System.out', 'Keyboard', 'BufferedReader', 'a', 'La clase Scanner del paquete java.util permite leer datos del teclado. Se crea con: Scanner leer = new Scanner(System.in); donde System.in representa la entrada estándar (teclado).'),
  (82, 'Scanner y entrada de datos', '¿Cuál es la instrucción correcta para importar la clase Scanner?', 'import Scanner;', 'include Scanner;', 'import java.util.Scanner;', 'using java.Scanner;', 'c', 'La clase Scanner pertenece al paquete java.util, por lo que se importa con: import java.util.Scanner; al inicio del archivo .java, antes de la declaración de la clase.'),
  (83, 'Scanner y entrada de datos', '¿Qué método de Scanner se usa para leer un número entero?', 'nextString()', 'readInt()', 'nextLine()', 'nextInt()', 'd', 'nextInt() lee el siguiente token de la entrada y lo interpreta como un entero. Para otros tipos: nextFloat(), nextDouble(), nextLine() (cadena completa), next() (palabra).'),
  (84, 'Scanner y entrada de datos', '¿Qué método de Scanner se usa para leer una cadena de texto completa (con espacios)?', 'nextString()', 'readLine()', 'next()', 'nextLine()', 'd', 'nextLine() lee toda la línea incluyendo espacios hasta el salto de línea. En cambio, next() solo lee hasta el primer espacio en blanco.'),
  (85, 'Scanner y entrada de datos', '¿Por qué se necesita escribir leer.nextLine(); después de leer.nextInt(); antes de leer una cadena?', 'No es necesario, es código redundante', 'Para convertir el entero a String', 'Para cerrar el Scanner', 'Para limpiar el buffer del teclado, ya que nextInt() deja el salto de línea pendiente', 'd', 'nextInt() lee solo el número pero deja el carácter de salto de línea (\n) en el buffer. Si después se llama nextLine(), leería esa línea vacía. El nextLine() intermedio consume ese \n residual.'),
  (86, 'Scanner y entrada de datos', '¿Cuál es la forma correcta de crear un objeto Scanner para leer del teclado?', 'Scanner leer = new Scanner(System.in);', 'Scanner leer = new Scanner(System.out);', 'Scanner leer = Scanner(System.in);', 'Scanner leer = new Scanner();', 'a', 'Se usa new Scanner(System.in) donde System.in es el flujo de entrada estándar (teclado). La opción a) falta new. La c) no tiene argumento. La d) usa System.out que es para salida.'),
  (87, 'Scanner y entrada de datos', 'En el ejemplo de PruebaPersona2, ¿cómo se guarda el nombre de Juanito leído del teclado?', 'juanito.setNombre(leer.nextLine());', 'juanito.nombre = leer.nextLine();', 'juanito = leer.nextLine();', 'Persona.nombre = leer.nextLine();', 'a', 'Como nombre es private, se usa el setter: juanito.setNombre(leer.nextLine()); El argumento leer.nextLine() lee la cadena del teclado y la pasa directamente al setter.'),
  (88, 'Scanner y entrada de datos', '¿Qué método de Scanner se usa para leer un valor de tipo float?', 'nextFloat()', 'readFloat()', 'nextDouble()', 'nextDecimal()', 'a', 'nextFloat() lee el siguiente token y lo convierte a float. Para double se usa nextDouble(). Ambos pueden lanzar InputMismatchException si el usuario introduce algo que no es número.'),
  (89, 'Scanner y entrada de datos', '¿Qué hacían los métodos pedirDatos() y mostrarDatos() que se pedían en la Tarea 5?', 'pedirDatos() leía de un archivo y mostrarDatos() escribía en un archivo', 'Ambos métodos eran constructores de la clase', 'pedirDatos() creaba el objeto y mostrarDatos() lo destruía', 'pedirDatos() usaba Scanner para leer los atributos del teclado y mostrarDatos() imprimía los valores de los atributos', 'd', 'pedirDatos() implementaba un Scanner dentro de la clase de diseño para solicitar al usuario cada atributo. mostrarDatos() imprimía los valores almacenados usando System.out.println.'),
  (90, 'Scanner y entrada de datos', '¿Cómo se lee un solo carácter del teclado usando Scanner?', 'leer.readChar()', 'leer.nextChar()', 'leer.next(char)', 'leer.nextLine().charAt(0)', 'd', 'Scanner no tiene un método nextChar(). La técnica usada es leer una línea o palabra y extraer el primer carácter: leer.nextLine().charAt(0), como se ve en el ejemplo de PruebaPaciente.'),
  (91, 'Arreglos de objetos', '¿Cuál es la sintaxis correcta para declarar un arreglo de objetos de tipo Paciente?', 'Array<Paciente> listaPacientes = new Array(5);', 'Paciente listaPacientes = new Paciente[5];', 'Paciente listaPacientes[] = new Paciente();', 'Paciente[] listaPacientes = new Paciente[5];', 'd', 'La sintaxis es: Tipo[] nombre = new Tipo[tamaño]; Esto crea un arreglo con 5 posiciones, pero cada posición es null hasta que se asigne un objeto con new Paciente().'),
  (92, 'Arreglos de objetos', '¿Qué valor tienen las posiciones de un arreglo de objetos recién creado?', 'Un objeto creado con el constructor mínimo', 'null (no apuntan a ningún objeto todavía)', 'Un objeto vacío', '0', 'b', 'Al crear un arreglo de objetos con new Tipo[n], todas las posiciones se inicializan en null. Se debe asignar un objeto a cada posición: arreglo[i] = new Tipo(); antes de usarla.'),
  (93, 'Arreglos de objetos', '¿Cómo se accede al atributo nombre del tercer paciente en un arreglo listaPacientes?', 'listaPacientes(2).get_nombre()', 'listaPacientes[2].get_nombre()', 'listaPacientes[3].get_nombre()', 'listaPacientes.get_nombre(2)', 'b', 'Los arreglos en Java empiezan en índice 0, por lo que el tercer elemento está en la posición 2. Se accede al método getter usando la notación: arreglo[indice].metodo().'),
  (94, 'Arreglos de objetos', '¿Qué diferencia hay entre un arreglo de tipos primitivos y un arreglo de objetos?', 'No hay ninguna diferencia', 'Los arreglos de primitivos no existen en Java', 'Los arreglos de objetos no necesitan tamaño al crearse', 'El arreglo de primitivos almacena valores directamente; el de objetos almacena referencias (null inicialmente) que deben apuntar a objetos creados con new', 'd', 'int[] nums = new int[3]; crea 3 posiciones con valor 0. Persona[] p = new Persona[3]; crea 3 posiciones con valor null que necesitan p[i] = new Persona(); para ser usadas.'),
  (95, 'Arreglos de objetos', '¿Qué estructura de control se usa típicamente para recorrer un arreglo de objetos?', 'while únicamente', 'try-catch', 'El ciclo for', 'switch-case', 'c', 'El ciclo for es la estructura más común: for(int i = 0; i < arreglo.length; i++) { ... } permite acceder a cada posición del arreglo usando el índice i.'),
  (96, 'Arreglos de objetos', '¿Qué propiedad del arreglo se usa para obtener su tamaño?', 'arreglo.count()', 'arreglo.size()', 'arreglo.length', 'arreglo.getSize()', 'c', 'En Java, los arreglos tienen la propiedad length (sin paréntesis) que indica cuántos elementos puede almacenar. Es diferente de length() de String o size() de ArrayList.'),
  (97, 'Arreglos de objetos', 'En el ejemplo de PruebaPaciente, ¿cómo se crea un arreglo cuyo tamaño se define en tiempo de ejecución?', 'El tamaño siempre debe ser una constante', 'Se usa ArrayList en lugar de arreglo', 'Se lee el tamaño con Scanner y luego se crea: listaPacientes = new Paciente[pacientes];', 'Paciente[] lista = new Paciente[]; sin tamaño', 'c', 'En PruebaPaciente se lee el número de pacientes con Scanner y ese valor se usa para dimensionar el arreglo: pacientes = leer.nextInt(); listaPacientes = new Paciente[pacientes];'),
  (98, 'Arreglos de objetos', '¿Qué sucede si se intenta acceder a arreglo[i] cuando arreglo[i] es null?', 'Se lanza una NullPointerException en tiempo de ejecución', 'No pasa nada, simplemente se ignora', 'Se crea automáticamente un objeto en esa posición', 'Retorna 0', 'a', 'Si se intenta llamar a un método o acceder a un atributo de una posición null, Java lanza NullPointerException. Por eso en Proyecto.java se verifica: if(personas[i] != null) antes de usarlo.'),
  (99, 'Arreglos de objetos', '¿Cómo se asigna un nuevo objeto Paciente en la posición i de un arreglo?', 'listaPacientes(i) = new Paciente();', 'listaPacientes[i] = new Paciente();', 'listaPacientes[i] = Paciente();', 'listaPacientes.add(new Paciente());', 'b', 'Se usa la notación de corchetes para indicar la posición y se asigna un nuevo objeto: listaPacientes[i] = new Paciente(); Esto reemplaza el null con una referencia al nuevo objeto.'),
  (100, 'Arreglos de objetos', 'En la Tarea 7, ¿qué se pedía hacer con un arreglo de objetos y un ciclo for?', 'Eliminar los objetos del arreglo uno por uno', 'Recorrer el arreglo con for para que cada objeto use pedirDatos(), y luego recorrer de nuevo para verificar que los datos se guardaron correctamente', 'Copiar el arreglo en otro arreglo más grande', 'Ordenar los objetos del arreglo alfabéticamente', 'b', 'La Tarea 7 pedía recorrer el arreglo con for para invocar pedirDatos() en cada objeto (captura), y después recorrer nuevamente para mostrar/verificar los datos almacenados.');

-- Verificar carga:
SELECT COUNT(*) AS total_preguntas FROM preguntas;